tool.command:
@CMD_UNZIP_ZARR@
mkdir -p output_dir &&
## Determine the SpatialData directory name SDATA_DIR=\$(find . -maxdepth 1 -name "*.zarr" -type d | head -n 1) &&
## Run patchify sopa patchify #if $patch_type.type == 'image' image --patch-width-pixel $patch_type.patch_width_pixel --patch-overlap-pixel $patch_type.patch_overlap_pixel #if $patch_type.channels #for $channel in str($patch_type.channels).split(',') --channels '$channel' #end for #end if #else transcripts --patch-width-microns $patch_type.patch_width_microns --patch-overlap-microns $patch_type.patch_overlap_microns #if str($patch_type.prior_shapes_key) != '' --prior-shapes-key '$patch_type.prior_shapes_key' #end if #if str($patch_type.unassigned_value) != '' --unassigned-value '$patch_type.unassigned_value' #end if #end if "\${SDATA_DIR}" &&
## Move to output directory mv "\${SDATA_DIR}" output_dir/ &&
@CMD_ZIP_ZARR@
